业"}, {"labelCode": "has_patent_invention", "labelDefinition": "该企业拥有一项或多项发明专利。发明专利是指针对产品、方法或其改进所提出的新技术方案。", "labelName": "拥有发明专利"}, {"labelCode": "pat_grant_top", "labelDefinition": "据企业官方和专利局网站信息显示，该企业在电通信技术领域获得的专利授权数量在同行业位于前列。", "labelName": "专利授权量同领域前10%"}, {"labelCode": "tech_layout_leader", "labelDefinition": "该企业所采用的技术或技术路线已经或正在成为该行业的主流趋势，相比同行业具有较高的市场竞争力和创新能力。", "labelName": "技术布局行业领先"}, {"labelCode": "has_patent_green", "labelDefinition": "该企业拥有以绿色低碳技术为发明主题的专利。绿色低碳技术是指通过传统能源清洁利用、节能增效、新能源利用和温室气体捕集利用封存等实现减碳、零碳和负碳效果的有关技术。", "labelName": "拥有绿色低碳技术"}, {"labelCode": "own_independent_brand", "labelDefinition": "该企业拥有铸泰科技自主品牌。", "labelName": "拥有自主品牌"}, {"labelCode": "college_employment_contribution", "labelDefinition": "据公开网络招聘信息显示，该企业在近1年内有发布过大学生就业岗位，助力大学生就业。", "labelName": "大学生就业贡献", "labelTranslateName": "欢迎应届生应聘"}], "showTypeUrl": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20250520/ptcard_128e85b893a640e8940c74c70daada54.png", "showTypeUrlDark": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20251208/a7401c7dc5b291eef900ff6b78327e18_f2a16bd811034ae78dea2e01b9945aee.png", "smallHrLogoUrl": "https://img01.51jobcdn.com/imehire/userportrait/default/li_portrait_female_006_small.png?v=20260317", "term": "0", "termStr": "全职", "triggerBatchDeliver": true, "updateDateTime": "2026-04-09 16:30:47", "userInteractionOnlineLabel": 2, "workAreaCode": "040300", "workYear": "5", "workYearString": "3年及以上"}

